from agent import *from models.products import *import redef serialize_text(text):    text = re.sub(r'<[^>]+>|\[.*?]', '', text).replace('<', '<').replace('&', '&')    return textdef strip_namespace(data):    tmp = data.content_file + ".tmp"    out = file(tmp, "w")    for line in file(data.content_file):        line = line.replace('<ns0', '<')        line = line.replace('ns0:', '')        line = line.replace(' xmlns', ' abcde=')        out.write(line + "\n")    out.close()    os.rename(tmp, data.content_file)def run(context, session):    session.browser.use_new_parser = True    session.queue(Request("https://bgr.com/reviews/"), process_category, dict())def process_category(data, context, session):    strip_namespace(data)    cats = data.xpath('//div[@class="subcategories"]/ul/li/a')    for cat in cats:        name = cat.xpath('text()').string()        url = cat.xpath('@href').string()        if name and url:            session.queue(Request(url), process_revlist, dict(cat=name))    # Not all revs in categories    process_revlist(data, context, session)def process_revlist(data, context, session):    strip_namespace(data)    revs = data.xpath('//div[@class="article-description"]/h3/a')    for rev in revs:        title = rev.xpath('text()').string()        url = rev.xpath('@href').string()        session.queue(Request(url), process_review, dict(context, title=title, url=url))    next_url = data.xpath('//a[@id="next-page"]/@href').string()    if next_url:        session.queue(Request(next_url), process_revlist, dict(context))def process_review(data, context, session):    strip_namespace(data)    product = Product()    product.name = data.xpath('//div[@class="top"]//div[@class="review-title"]/text()').string() or context['title'].split(' Review:')[0].split(' review:')[0].split(' Review')[0].split(' review')[0]    product.url = data.xpath('//table[contains(., "Buy From")]//td/a/@href').string() or context['url']    product.manufacturer = data.xpath('//tr[th[regexp:test(., "Brand", "i")]]/td/text()').string()    product.ssid = data.xpath('//h1/@data-post-id').string()    product.category = context.get('cat', 'Tech').replace('Reviews', '').strip()    ean = data.xpath('//tr[th[regexp:test(., "Identification Number", "i") or regexp:test(., "upc", "i")]]/td/text()').string()    if ean and ean.isdigit():        product.properties.append(ProductProperty(type='id.ean', value=ean))    mpn = data.xpath('//tr[th[regexp:test(., "^\s*ASIN", "i")]]/td/text()').string()    if mpn:        product.properties.append(ProductProperty(type='id.manufacturer', value=mpn))    review = Review()    review.title = context['title']    review.url = context['url']    review.ssid = product.ssid    review.type = "pro"    date = data.xpath('//meta[contains(@property, "published_time")]/@content').string()    if date:        review.date = date.split('T')[0]    author = data.xpath('//a[@class="byline-author"]').first()    if author:        author_name = author.xpath('text()').string()        author_url = author.xpath('@href').string()        author_ssid = author_url.strip('/').split('/')[-1]        review.authors.append(Person(name=author_name, profile_url=author_url, ssid=author_ssid))    pros = data.xpath('//*[@class="pro"]//li/text()[normalize-space()]').strings() or data.xpath('//ul[@class="pros"]/li/text()').strings() or data.xpath('//*[@class="pro"]/following-sibling::ul[1]//li//text()[normalize-space()]').strings()    for pro in pros:        pro = pro.strip('-_—+*., ')        if pro:            review.add_property(type='pros', value=pro)    cons = data.xpath('//*[@class="con"]//li/text()[normalize-space()]').strings() or data.xpath('//ul[@class="cons"]/li/text()').strings() or data.xpath('//*[@class="con"]/following-sibling::ul[1]//li//text()[normalize-space()]').strings()    for con in cons:        con = con.strip('-_—+*., ')        if con:            review.add_property(type='cons', value=con)    grade_overall = data.xpath('//span[@class="rating" or @class="score-number"]/text()').string()    if grade_overall:        grade_overall = float(grade_overall.split('/')[0].split(': ')[-1].replace(',', '.'))        if grade_overall > 0:            review.grades.append(Grade(type="overall", value=grade_overall, best=10.0))    summary = data.xpath('//div[@class="top"]//div[@class="review-desc"]//text()').string(multiple=True) or data.xpath('//div[@class="dc-description"]//p//text()').string(multiple=True)    if summary:        summary = serialize_text(summary).strip()        if summary:            review.add_property(type='summary', value=summary)    conclusion = data.xpath('//div[@class="article"]//p[preceding::h2[regexp:test(@id, "^h-conclusion") or regexp:test(., "wrap-up") or regexp:test(., "conclusion") or regexp:test(., "^h-should-you") or regexp:test(., "^\s*Conclusion", "i")]]//text()').string(multiple=True)    if conclusion:        conclusion = serialize_text(conclusion).strip()        if conclusion:            review.add_property(type="conclusion", value=conclusion)    excerpt = data.xpath('//div[@class="article"]//p[not(ancestor::div[contains(@class, "detailed-commerce")])][not(@class="disclaimer")][not(preceding::h2[regexp:test(@id, "^h-conclusion") or regexp:test(., "wrap-up") or regexp:test(., "conclusion") or regexp:test(., "^h-should-you") or regexp:test(., "^\s*Conclusion", "i")])]//text()').string(multiple=True)    if excerpt:        excerpt = serialize_text(excerpt).strip()        if excerpt:            review.add_property(type="excerpt", value=excerpt)            product.reviews.append(review)            session.emit(product)